var e=JSON.parse(`[{"id":"L15_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"키하! 캬하하하하하하하하하하────────!","JPN":"キャハ！　キャハハハハハハハハハ────────！","ENG":"Kihah! Kyahahahahahahahahahaha────────!","TWN":"呀哈！咔哈哈哈哈哈哈哈哈哈哈────────！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"이거 끝내주는데! 역시 자유로운 육체가 있다는 건 행복한 일이이구만──!","JPN":"すげぇじゃねぇか！　やっぱり自由な身体があるって幸せだなあ──！","ENG":"This is incredible! Having a free body of my own really is bliss──!","TWN":"這真是超爽的耶！果然擁有自由的肉體就是幸福啊──！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"그런 건가…….","JPN":"そうか……","ENG":"Is that so...","TWN":"原來如此……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"베는 동작과 실제 참격 사이에 간극이 있군.","JPN":"斬る動作と実際の斬撃の間に隙がある。","ENG":"There's a gap between the swing and the actual slash.","TWN":"揮砍動作與實際斬擊之間有時間差。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"기습에 특화된 능력. 네놈의 검은 한치 앞의 미래를 베는 건가?","JPN":"奇襲に特化した能力。貴様の剣は一足先の未来を斬るのか？","ENG":"An ability specialized for ambushes. Does your blade cut the immediate future itself?","TWN":"專精於偷襲的能力。你的劍，是要斬斷眼前的未來嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"오, 한 눈에 알아봤다고?","JPN":"お、一目でわかったのか？","ENG":"Oh? You figured it out at a glance?","TWN":"喔，一眼就被你看穿了？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서 어쩔 건데? 네가 뭘 할 수 있지?","JPN":"それで？　お前に何ができる？","ENG":"So what now? What can you even do?","TWN":"那又怎樣？你能做什麼？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"신성을 각성하여, 제법 특이한 능력을 발현한 모양이지만…….","JPN":"神聖を覚醒し、かなり特殊な能力が発現したようだが……","ENG":"It seems you've awakened Divinity and manifested a rather unusual ability, but...","TWN":"看來你覺醒神性，發現了相當特殊的能力……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"아직은 허술하군.","JPN":"まだ隙だらけだ。","ENG":"You're still sloppy.","TWN":"不過，還不專精。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"꾸엑……!?","JPN":"くえっ……！？","ENG":"Agh...?!","TWN":"咕噁……！？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L36_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"네놈을 여기서 살려 두면, 틀림없이 어머니의 적수가 되겠지.","JPN":"貴様をここで生かしておけば、間違いなくお母さんの敵になるだろう。","ENG":"If I leave you alive here, you'll surely become Mother's equal someday.","TWN":"如果讓你活著離開這裡，絕對會成為母親的勁敵。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L37_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"큭큭. 뭐야, 누님?","JPN":"くくっ、何だよ、姉さん。","ENG":"Keke. What is it, Sis?","TWN":"嘿嘿，怎麼了，姐姐？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"벌써 이만한 아들도 있어…? 오호, 재미 좀 봤나 본데……?","JPN":"もうこんなに大きい息子がいるのか……？　へえ、結構遊んだんだな……？","ENG":"You've already got a kid this big...? Oho, looks like you've had some fun, huh...?","TWN":"已經有這麼大的兒子了啊？哦～看來過得挺滋潤的嘛……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"쓸데없는 소리로군. 이대로 질식해 죽어라……!","JPN":"無駄口を。このまま窒息して死ね……！","ENG":"Useless chatter. Suffocate and die right here...!","TWN":"無聊的胡言亂語。你就這樣窒息而死吧……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"으갸아아아아악!! 야, 살려줘! 빨리 살려달라고오오오오!! 버네에엣……!!","JPN":"ぎゃああああっ！！　おい、助けてくれ！　早く助けてくれよおおお！！　バーネット……！！","ENG":"Gyaaaaaaah!! Hey, save me! Hurry, save me already!! Burneeetttttt...!!","TWN":"嗚啊啊啊啊啊啊！！喂，救命啊！快救我啦啊啊啊啊！！伯內特……！！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L42_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"이러다 리온 죽는다!? 진짜로 리온 죽는다아아아아……!?","JPN":"このままじゃリオン死ぬんだぞ！？　マジでリオン死ぬからなああ！？","ENG":"At this rate Liona's gonna die! She's really gonna dieee...!","TWN":"這樣下去萊恩會死的！？真的會死啊啊啊啊啊啊……！？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"큭, 가소롭군……!","JPN":"ちっ、くだらない……！","ENG":"Kgh, how ridiculous...!","TWN":"嘖，真可笑……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L47_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"너 따위가 감히 날 상대할 셈인가?","JPN":"貴様ごときが俺の相手をしようというのか？","ENG":"You think you're worthy of facing me?","TWN":"就憑你，也敢與我為敵嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L48_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그래, 네 상대는 나야! 그러니까 녀석을 풀어줘!","JPN":"ああ、お前の相手は俺だ！　だからそいつを放せ！","ENG":"Yeah, your opponent is me! So let him go!","TWN":"沒錯，你的對手是我！所以放了那傢伙！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"저 파편 녀석은 몰라도, 리오나를 일방적으로 죽게 내버려 둘 수는 없어……!","JPN":"あの破片のやつはともかく、リオナを死なせるわけにはいかないんだ……！","ENG":"I don't care about that Fragment, but I won't let Liona die like this...!","TWN":"就算不管那個碎片，我也不能眼睜睜看著萊歐娜被殺……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그러기 위해서, 이 방패를 짊어진 거니까!","JPN":"そのために俺はこの盾を引き継いだんだ！","ENG":"That's why I carry this shield!","TWN":"正因為如此，我才背負著這面盾牌！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"괜찮아, 루키?","JPN":"大丈夫か、ルーキー？","ENG":"You okay, rookie?","TWN":"沒事吧，菜鳥？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"으으, 죽는 줄 알았네……!","JPN":"うう、死ぬかと思った……！","ENG":"Ugh... I seriously thought I was dead...!","TWN":"唔唔，我以為我要死了……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"놈팽이! <color=#ffd34c>특별 관리 대상</color>이라면서! 그럼, 특별 관리를 하란 말이야……!","JPN":"おい、チンピラ！　<color=#ffd34c>特別管理対象</color>なんだろ！　なら特別に管理しろってんだ……！","ENG":"You scumbag! You said I was under <color=#ffd34c>special surveillance</color>! Then do some special surveilling already...!","TWN":"你這混帳！不是說是<color=#ffd34c>特別管理對象</color>嗎！那就給我好好特別管理啊……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 너! 설마 이 둔탱이 좋아해? 그럼, 가슴이라도 만지게 해줘?","JPN":"それにお前！　まさかこのどんくさいのが好きなのか？　胸でも触らせてやろうか？","ENG":"And you! Do you like this dullard or something? You want me to let you grope her chest?","TWN":"還有你！該不會喜歡這個笨蛋吧？那至少讓我摸摸胸部啊？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"……괜히 구했나, 이거?","JPN":"……助けないほうがよかったか、これ。","ENG":"...I saved you for nothing, didn't I?","TWN":"……我是不是白救你了？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"크윽……!!","JPN":"くっ……！！","ENG":"Kgh...!!","TWN":"咳……！！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_HATE"},"R":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_HIT_METAL_05"},{"id":"L13_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"오랜만이에요, 버넷.","JPN":"久しぶりですね、バーネット。","ENG":"It's been a while, Burnett.","TWN":"好久不見了，伯內特。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_13"},{"id":"L14_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"마침 놀이 상대를 찾고 있었는데, 잘 됐네요.","JPN":"ちょうど遊び相手を探していたところなんです。","ENG":"I was just looking for someone to play with. This works out nicely.","TWN":"我正好在找玩伴呢，真是太好了。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"저랑 같이 놀아주시겠어요?","JPN":"一緒に遊んでくれますか？","ENG":"Care to play with me?","TWN":"要不要陪我一起玩啊？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","text":{"KOREA":"제 기관원에게 손 떼세요, 괴물.","JPN":"私の機関員から手を離しなさい、化け物。","ENG":"Hands off my agent, monster.","TWN":"把手從我的機關成員身上拿開，怪物。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"후후, 설마 질투인가요? 못 본 사이에 귀여워지셨네요, 기관장님?","JPN":"ふふ、まさか嫉妬してるんですか？　しばらく見ない間に可愛くなりましたね、機関長。","ENG":"Hehe, jealous? You've gotten cuter since I last saw you, Chief.","TWN":"呵呵，你該不會在吃醋吧？我們沒有見面的這段時間，你變得挺可愛的嘛，機關長？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"어디 질투는 무슨 맛이 나려나…… ","JPN":"嫉妬はどんな味がするのでしょう…… ","ENG":"Now I wonder... What does jealousy taste like...?","TWN":"我好像聞到嫉妒的味道呢…… "},"stage":{"bg":"SKY_RED","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"음!?","JPN":"ん！？","ENG":"Mm?!","TWN":"嗯！？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_ReinforcedA_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"에델, 호수의 기사가 상처를 입은 지금이 기회입니다.","JPN":"エデル、湖の騎士が負傷した今がチャンスです。","ENG":"Edel, now is our chance while the Knight of the Lake is wounded.","TWN":"艾瑟兒，湖水騎士受傷了，現在正是機會。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"방해자를 탐식하도록 하세요.","JPN":"邪魔者を貪食しなさい。","ENG":"Have her devour the Disturber.","TWN":"去吞噬那個妨礙者吧。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"크읏! 이런, 어머니를 잊고 있었네요?","JPN":"くっ！　お母さんのことを忘れていましたね。","ENG":"Kgh! Oh my, I almost forgot about Mother.","TWN":"嘖！哎呀，我把母親給忘了呢？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE"},{"id":"L30_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"그런가요? 그거 잘 됐네요.","JPN":"そうですか？　それはよかったです。","ENG":"Is that so? How convenient.","TWN":"是嗎？那真是太好了。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"저희는 줄곧 당신만을 노리고 있었으니까!","JPN":"我々はずっとあなただけを狙っていましたから！","ENG":"We've been aiming for you all along!","TWN":"因為我們從頭到尾，目標就只有你啊！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"네놈, 마이트너……!","JPN":"貴様、マイトナー……！","ENG":"Meitner...!","TWN":"你這傢伙，邁特納……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"소용없어! 네 사슬은 이쪽에서 막아내겠어……!","JPN":"無駄だ！　お前の鎖は俺が止める……！","ENG":"It's useless! I'll block your chains from here...!","TWN":"沒用的！我要擋住你的鎖鏈……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ONLY_CHARADE_C_CRIMSON_CHAIN_2"},{"id":"L37_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"큭, 애송이 주제에!","JPN":"くっ、邪魔だ、小僧！","ENG":"Tch, insolent whelp!","TWN":"嘖，區區小鬼！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"일단은 기관장으로서 감사를 표하죠, 맥크레디.","JPN":"とりあえず、機関長としてお礼を申し上げますわ、マクレディー。","ENG":"For now, allow me to express my thanks as the Chief, MacCready.","TWN":"那麼作為機關長，我就先向你道謝吧，麥克蕾蒂。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"아니, 이제는 학회장님이라고 불러드려야 할까요?","JPN":"いいえ、今は学会長とお呼びすべきでしょうか。","ENG":"Or should I address you as the President now?","TWN":"不，現在是不是該稱呼你為學會長了呢？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"어느 쪽이든 상관없어요.","JPN":"どちらでも構いません。","ENG":"Either is fine.","TWN":"怎麼叫我都無所謂。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"지금은 교단을 막는 게 더 시급하니까요.","JPN":"今は教団を止めるほうが先です。","ENG":"Stopping the faction takes priority right now.","TWN":"現在更要緊的是阻止教團。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_QM","text":{"KOREA":"그래, 그대의 말이 옳아.","JPN":"ああ、そのとおりだ。","ENG":"Yes, your words are correct.","TWN":"是啊，你說得對。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_QM","text":{"KOREA":"도시를 지키는 것은 실패했지만, 그럼에도 우리는 싸워야겠지.","JPN":"都市を守ることには失敗したが、それでも私たちは戦わなければならない。","ENG":"We failed to protect the city, but even so, we must keep fighting.","TWN":"雖然沒能守住城市，但即便如此，我們仍必須戰鬥。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_QM","text":{"KOREA":"우리의 정의를 관철하기 위해서.","JPN":"私たちの正義を貫くために。","ENG":"To see our justice carried through.","TWN":"為了貫徹我們的正義。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"전선에서 일시적으로 이탈했던 조디악 나이츠.","JPN":"戦線で一時的に離脱したゾディアックナイツ。","ENG":"The Zodiac Knights, who temporarily withdrew from the front line.","TWN":"暫時脫離前線的十二宮騎士團。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L50_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"선봉대로서 이 전장에 복귀했음을 모두에게 알린다……!","JPN":"先鋒隊として戦場に復帰したことを告げる……！","ENG":"I hereby announce to all that we have returned to this battlefield as the vanguard...!","TWN":"在此向所有人宣告，我們已作為先鋒重返這片戰場……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"모두들 괜찮아요?","JPN":"みんな大丈夫ですか？","ENG":"Is everyone all right?","TWN":"大家都沒事吧？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"다들 아직 끝난 거 아니지? 도와주러 왔다고!","JPN":"まだ終わってないよな？　助けに来たから！","ENG":"It's not over yet, is it? We came to help!","TWN":"還沒結束對吧？我來幫忙了！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"TITAN_FAW_TRIAINA_NULL","text":{"KOREA":"모듈 아머 체인지! 트리아이나 플랜!","JPN":"モジュールアーマーチェンジ！　トリアイナプラン！","ENG":"Module armor change! Triaina Plan!","TWN":"裝甲模組變換！三叉戟計畫！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_TRIAINA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_TECH_03"},{"id":"L8_1","type":"dialog","speaker":"TITAN_FAW_TRIAINA_NULL","text":{"KOREA":"세기말 결전 병기, 여기 도착! 이 도시의 전쟁을 끝내러 왔다!","JPN":"世紀末決戦兵器、ここに参上！　この都市の戦争を終わらせに参ったぞ！","ENG":"Apocalyptic massive weapon of destruction, arriving on site! I'm here to end this city's war!","TWN":"世紀末決戰兵器，抵達現場！我來結束這座城市的戰爭！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_TRIAINA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"정말! 대체 이게 어떻게 된 거야?","JPN":"もう！　いったいどうなってるの？","ENG":"Seriously! What on earth just happened?","TWN":"真是的！這到底是怎麼回事啊？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"정신을 차려 보니까, 작전 구역으로부터 3km나 떨어진 곳이었다고!","JPN":"気がつけば作戦区域から3kmも離れた場所だったのよ！","ENG":"When I came to, I was three kilometers away from the operation zone!","TWN":"一回過神，竟然已經離作戰區域3公里了！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"작전이 실패했어요. 그리고 폭발이 일어났죠.","JPN":"作戦が失敗して、爆発が起きました。","ENG":"The operation failed. And then there was an explosion.","TWN":"作戰失敗了，接著又發生爆炸。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"하지만 작전 인원 대부분이 갑자기 사라져 버려서 폭발을 피할 수 있었어요.","JPN":"でも作戦メンバーのほとんどが突然消えたおかげで、爆発に巻き込まれず済んだのです。","ENG":"But most of the personnel suddenly vanished, so we were able to avoid it.","TWN":"不過，大部分作戰人員突然消失，反而躲過了爆炸。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"사라져 버렸다고? 허신도 갑자기 사라졌잖아?","JPN":"消えた？　虚神も突然消えたじゃない。","ENG":"Vanished? The Hollow God disappeared all of a sudden too, didn't it?","TWN":"消失？虛神不是也突然消失了嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"어라……?","JPN":"あれ……？","ENG":"Huh...?","TWN":"咦……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"감사합니다, 레지나 님.","JPN":"ありがとうございます、レジーナ様。","ENG":"Thank you, Miss Regina.","TWN":"謝謝你，蕾佳娜。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L22_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"당신이 아니었다면, 여기 있는 대부분이 죽거나 큰 부상을 입었겠죠.","JPN":"あなたでなければ、ここにいるほとんどは死ぬか深手を負っていたでしょう。","ENG":"If it weren't for you, most of us here would have been killed or gravely injured.","TWN":"若不是您，大多數在場的人不是死亡就是重傷了。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"과찬이에요, 람다.","JPN":"当然のことをやったまでです、ラムダ。","ENG":"You flatter me, Lamda.","TWN":"你過獎了，蘭達。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"영지의 질서를 바로잡는 것은 학회장의 의무니까요.","JPN":"領地の秩序を立たすことは、学会長の義務ですから。","ENG":"Maintaining order within my estate is the President's duty.","TWN":"整頓領地的秩序，是學會長的職責。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"하지만…….","JPN":"ですが……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"아무래도 저는…….","JPN":"どうやら私は……","ENG":"It seems I...","TWN":"無論怎麼說，我……"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"제 영지조차도 제대로 지켜내지 못한 모양이로군요.","JPN":"自分の領地すら、まともに守りきれなかったようです。","ENG":"I couldn't even properly protect my own estate.","TWN":"看來我連自己的領地……都沒能好好守住呢。"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TOTO_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐야, 이건…!? 지진이라고……?","JPN":"なんだ、これは……！？　地震だと……？","ENG":"What is this...?! An earthquake...?","TWN":"這是怎麼回事……！？地震嗎……？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TOTO_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"슬슬 한계인 모양이군요.","JPN":"そろそろ限界のようですね。","ENG":"Looks like we're reaching the limit.","TWN":"看來差不多到極限了。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"대균열로부터 뻗어 나온 뿌리가 이곳의 지반을 뚫고 나오고 있어요.","JPN":"大亀裂から伸びた根が、ここの地盤を貫通してきています。","ENG":"Roots extending from the Grand Dimension Crevice are breaking through the ground here.","TWN":"從大峽谷延伸出的根，正穿破這一帶地面。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"곧 이 구역도 클리파에 의해 오염되겠죠.","JPN":"もうすぐこの区域もクリファによって汚染されるでしょう。","ENG":"This entire area will soon be contaminated by Qlipha.","TWN":"不久後，這個區域也會被逆卡巴拉污染吧。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"어머니시여, 외람되지만 저희에게 승산이 없습니다.","JPN":"お母さん、出過ぎたことを言うようですが、俺たちには勝ち目がありません。","ENG":"Mother, forgive me for saying this, but we have no chance of victory.","TWN":"母親大人，恕我直言，我們沒有勝算。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"이쯤에서 물러나고 다음을 기약하는 편이 좋겠습니다.","JPN":"この辺で撤退し、機を伺ったほうが良いかと。","ENG":"It would be wise to withdraw here and prepare for what comes next.","TWN":"不如就此撤退，為下一次做準備比較好。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"뭐, 아쉽지만 어쩔 수 없네요.","JPN":"まあ、残念ですが仕方ありませんね。","ENG":"Well, it's unfortunate, but it can't be helped.","TWN":"唉，雖然遺憾，但也沒辦法了。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"기사님도 다친 상처를 회복해야 하고, 저도 필요 이상으로 파편을 소모해 버렸어요.","JPN":"騎士様も傷を回復しないといけませんし、私も必要以上に破片を消耗してしまいました。","ENG":"You need time to recover your wounds, my knight, and I've expended more Fragments than I should have.","TWN":"騎士需要治療傷勢，我也消耗過多的碎片。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"흐응, 타이밍은 잘 잡았다고 생각했는데…….","JPN":"ふーん、タイミングはよかったと思ったのですが……","ENG":"Hmm, I thought the timing was perfect...","TWN":"哼，我還以為時機抓得不錯呢……"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_13"},{"id":"L46_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"아직 어머니와 전면전을 벌이기에는 역부족이었던 모양이네요.","JPN":"まだお母さんと正面から戦うには、役不足だったようですね。","ENG":"It seems we are still lacking to face Mother head-on.","TWN":"看來現在還不足以與母親正面開戰。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"그리고 전혀 예상치 못한 <color=#ffd34c>변수</color>도 있었고요.","JPN":"それに、想定外の<color=#ffd34c>変数</color>もありましたし。","ENG":"And there was an entirely unexpected <color=#ffd34c>variable</color> as well.","TWN":"還出現完全預料之外的<color=#ffd34c>變數</color>。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_NULL","text":{"KOREA":"송구합니다, 어머니.","JPN":"面目ありません、お母さん。","ENG":"My apologies, Mother.","TWN":"非常抱歉，母親。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"설마 도망칠 생각인가요, 방해자?","JPN":"まさか逃げるつもりですか？　邪魔者。","ENG":"Are you thinking of running away, Disturber?","TWN":"你該不會想逃跑吧，妨礙者？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS2"}}}},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"제가 그걸 빤히 지켜만 보고 있을 거라고 생각해요?","JPN":"我々がそれを許すとでも？","ENG":"Did you really think I'd just stand by and watch?","TWN":"你以為我會坐視不管嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS2"}}}},{"id":"L4_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"후후, 그렇게 자신만만하기에는 어머니도 제법 많은 힘을 소모하지 않으셨나요?","JPN":"ふふ、自信満々に言っている割には、お母さんもかなり力を消耗しているんじゃないですか？","ENG":"Hehe, aren't you being a bit overconfident when you've already expended so much power yourself, Mother?","TWN":"呵呵，表面上這麼有自信，母親您不也消耗很多力量嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"그건 여기서 당신을 탐식하면, 해결될 문제겠네요.","JPN":"それはここであなたを貪食すれば解決する問題です。","ENG":"Then devouring you here would solve that problem.","TWN":"那就只要在這裡吞噬你就沒問題了。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","text":{"KOREA":"그렇다면, 내 모든 것을 걸고 네놈들을 전부 길동무로 삼아주지.","JPN":"ならば、俺のすべてをかけて貴様ら全員を道連れにしてやる。","ENG":"In that case, I'll stake everything I have to drag you all down with me.","TWN":"既然如此，我就賭上我的一切，拉你們全部陪葬吧。"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRYDWEN_ESPR_CORRUPTED","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"재밌네요. 그런다고 제가 못할 줄 아나요?","JPN":"面白いですね。そんな脅しに怯むとでも思っているのですか？","ENG":"How amusing. Do you really think I couldn't handle that?","TWN":"真有趣。你以為我做不到嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그만하세요, 에델.","JPN":"やめなさい、エデル。","ENG":"That's enough, Edel.","TWN":"住手吧，艾瑟兒。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"하지만 레지나 님……!","JPN":"ですが、レジーナ様……！","ENG":"But Miss Regina...!","TWN":"蕾佳娜大人，可是……！"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"토 달지 마세요.","JPN":"口答えは許しません。","ENG":"Do not talk back to me.","TWN":"不要多說了。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"저는 제 영지에서 더 이상의 희생을 바라지 않습니다.","JPN":"私の領地でこれ以上の犠牲は出てほしくありません。","ENG":"I do not wish for any more sacrifices within my estate.","TWN":"我不希望在我的領地有更多人犧牲。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그러니 교단 측도 이쯤에서 물러나 주셨으면 좋겠군요.","JPN":"ですから教団側もこの辺でお引き取りください。","ENG":"So I would appreciate it if the faction withdrew at this point as well.","TWN":"所以希望教團也就此退下吧。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"어차피 당신들의 목적은 전조 현상을 가속하는 것 아니었나요?","JPN":"そもそもあなたたちの目的は、前兆現象を加速させることではありませんか？","ENG":"After all, wasn't your goal to accelerate the omen phenomenon?","TWN":"反正你們的目的，不就是加速前兆現象嗎？"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그렇다면 이미 소기의 목적은 달성했을 텐데요.","JPN":"なら、すでに目的は達成したはずです。","ENG":"If so, you've already achieved what you wanted.","TWN":"那樣的話，應該已經達成目的了。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"역시 현명한 처사예요, 레지나.","JPN":"賢明な判断です、レジーナ。","ENG":"As expected of you, Regina. A wise decision.","TWN":"果然是明智的判斷呢，蕾佳娜。"},"stage":{"bg":"CITY_CENTER3","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"그럼, 모두들 바이바이~","JPN":"では皆さん、バイバーイ～","ENG":"Well then, bye-bye, everyone!","TWN":"那麼，大家拜拜囉～"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EVE_PRYDWEN_ESPR_ON","text":{"KOREA":"다음 클리포트 게임에서 꼭 승리를 거두길 바랄게요.","JPN":"次のクリフォトゲームで勝利を掴み取ってくださいね。","ENG":"I hope you win the next Qliphoth Game.","TWN":"希望你們能在下一場逆卡巴拉遊戲中獲勝。"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_ESPR_ON","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};